it("should throw an error for a negative damage amount", () => {
  expect(() =>
    processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword" }],
        },
        {
          op: "claim",
          policy: 0,
          incident: {
            cause: "dragon attack",
            damages: [{ itemType: "sword", amount: -200 }],
          },
        },
      ],
    })
  ).toThrow();
});
